import json

# Load 2015 article metadata
metadata_file = locals()['var_functions.query_db:24']
with open(metadata_file, 'r') as f:
    articles_2015_metadata = json.load(f)

# Let's categorize articles by their title/description keywords
world_keywords = ['world', 'global', 'international', 'war', 'peace', 'united nations', 'european union', 'asia', 'europe', 'africa', 'america', 'australia', 'conflict', 'treaty', 'diplomatic']
sports_keywords = ['sport', 'game', 'olympic', 'world cup', 'championship', 'tournament', 'football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf']
business_keywords = ['stock', 'market', 'economy', 'business', 'company', 'corporation', 'profit', 'loss', 'revenue', 'shares', 'investment', 'wall st', 'nasdaq', 'dow', 'oil price', 'crude']
tech_keywords = ['technology', 'tech', 'science', 'software', 'computer', 'internet', 'digital', 'research', 'scientist', 'innovation', 'ai', 'artificial intelligence']

# Categorize the 5 sample articles
sample_articles = locals()['var_functions.query_db:38']
categories = {}

for article in sample_articles:
    title_desc = (article.get('title', '') + ' ' + article.get('description', '')).lower()

    if any(keyword in title_desc for keyword in sports_keywords):
        categories[article['article_id']] = 'Sports'
    elif any(keyword in title_desc for keyword in business_keywords):
        categories[article['article_id']] = 'Business'
    elif any(keyword in title_desc for keyword in tech_keywords):
        categories[article['article_id']] = 'Science/Technology'
    elif any(keyword in title_desc for keyword in world_keywords):
        categories[article['article_id']] = 'World'
    else:
        categories[article['article_id']] = 'Other'

print('__RESULT__:')
print(json.dumps({
    'categorized_sample': categories,
    'total_sample': len(categories)
}))

