import json

# Load 2015 metadata
metadata_file = locals()['var_functions.query_db:90']
with open(metadata_file, 'r') as f:
    articles_2015_metadata = json.load(f)

# Create region mapping
region_map = {article['article_id']: article['region'] for article in articles_2015_metadata}

# Count regions
region_counts = {}
for region in region_map.values():
    region_counts[region] = region_counts.get(region, 0) + 1

print('__RESULT__:')
print(json.dumps({
    'total_2015_articles': len(articles_2015_metadata),
    'region_counts': region_counts,
    'sample_regions': {k: region_map[k] for k in list(region_map.keys())[:10]}
}))

